module top_module(
  input [3:0] obf_in,
  output reg [3:0] out
);always @(*)
  begin
    if (obf_in >= 0 && obf_in <= 7) // Range 0 to 7
      out = obf_in << 1;
    else if (obf_in >= 8 && obf_in <= 15) // Range 8 to 15
      out = obf_in >> 1;
    else // Outside range 0 to 15
      out = 0;
  end

endmodule
